const updates    = $('getUpdates').first().json.result || [];
const tg         = $('Vault').first().json.data.data;
const stats      = $('Fetch stats').first().json;
const configChat = String(tg.chat_id);

const out = [];
let maxUpdateId = $('Load offset').first().json.last_update_id || 0;

function renderDigest(s) {
  const total = Number(s.local_calls) + Number(s.cloud_calls);
  const sov = total === 0 ? 'no AI calls' : `${(100 * s.local_calls / total).toFixed(1)}% local (${s.local_calls}/${total})`;
  return [
    '<b>Home AI — current snapshot</b>',
    '',
    '<b>Last 24h</b>',
    `• ${s.success}OK / ${s.failure}FAIL AI calls`,
    `• ${s.processed} events processed, ${s.failed} failed, ${s.in_flight} in flight`,
    `• ${s.firing} firing alerts, ${s.open} open dead letters`,
    `• ${s.classified_24h} emails classified, ${s.needs_review} invoices need review`,
    '',
    `<b>Sovereignty:</b> ${sov}`,
  ].join('\n');
}

function renderQueue(s) {
  return [
    '<b>Home AI — queue</b>',
    '',
    `• Open dead letters: ${s.open}`,
    `• Invoices needing review: ${s.needs_review}`,
    `• Events in flight: ${s.in_flight}`,
    `• Failing alerts: ${s.firing}`,
  ].join('\n');
}

function renderHelp() {
  return [
    '<b>Home AI — commands</b>',
    '/digest — current snapshot of last 24h activity',
    '/queue  — open dead letters + items needing review',
    '/help   — show this list',
  ].join('\n');
}

for (const u of updates) {
  if (u.update_id > maxUpdateId) maxUpdateId = u.update_id;
  const m = u.message;
  if (!m || !m.text) continue;
  const fromChat = String(m.chat?.id ?? '');
  if (fromChat !== configChat) continue;
  const text = m.text.trim();
  if (!text.startsWith('/')) continue;
  const cmd = text.split(/\s+/)[0].split('@')[0].toLowerCase();

  let reply;
  if      (cmd === '/digest') reply = renderDigest(stats);
  else if (cmd === '/queue')  reply = renderQueue(stats);
  else if (cmd === '/help' || cmd === '/start') reply = renderHelp();
  else reply = `Unknown command: ${cmd}\nTry /help`;

  out.push({ json: { _kind: 'reply', chat_id: tg.chat_id, bot_token: tg.bot_token, text: reply } });
}

// Always emit a control item so the offset gets persisted even when no commands ran.
out.push({ json: { _kind: 'control', max_update_id: maxUpdateId } });
return out;
